mapper.select:
/* selectDispatchHeadOrder */ SELECT CONCAT(TP.WAREKEY, TP.VHPLNKY) AS ROWKEY , TP.WAREKEY , MW.WHNAMLC , TP.VHPLNKY , TP.VOWNKEY , MV.VONAMLC , TP.VEHICKY , MH.VHCFNAM , MH.VHCSNAM , MH.VHCVRYN , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'VHCTNCD' AND COMCDVL = MH.VHCTNCD AND COUSEYN = 'Y') AS VHNAMLC , TP.VHCMAXW , MH.VHCTYPE , TP.DRVERNM , TP.DRVERPH , TP.DOCCATE , TP.DOCTYPE , MD.DOCCTNM , MD.DOCTYNM , TP.LOADKEY , MCL.COMCDTX as LONAMLC , TP.TPNSTAT , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'TPNSTAT' AND COMCDVL = TP.TPNSTAT AND COUSEYN = 'Y') AS PLNAMLC , TP.TPRILOC , (SELECT LOCANAM FROM ${userInfo.schema}.MLOCMA WHERE WAREKEY = #{param.warekey} AND LOCTYPE = 'STP' AND LOUSEYN = 'Y' AND LOCAKEY = TP.TPRILOC) AS TRLOCML , TP.SPRILOC , (SELECT LOCANAM FROM ${userInfo.schema}.MLOCMA WHERE WAREKEY = #{param.warekey} AND LOCTYPE = 'STP' AND LOUSEYN = 'Y' AND LOCAKEY = TP.SPRILOC) AS SRLOCML , TP.TRNMEMO , TP.MIXCUYN , DATE_FORMAT(TP.VHPDATE, '%Y-%m-%d') as VHPDATE , CASE WHEN TP.VHPTIME IS NULL OR TRIM(TP.VHPTIME) = '' THEN '' ELSE STR_TO_DATE(TP.VHPTIME, '%H%i%s') END as VHPTIME , DATE_FORMAT(TP.STPITDT, '%Y-%m-%d') as STPITDT , CASE WHEN TP.STPITTM IS NULL OR TRIM(TP.STPITTM) = '' THEN '' ELSE STR_TO_DATE(TP.STPITTM, '%H%i%s') END AS STPITTM , DATE_FORMAT(TP.TRNINDT, '%Y-%m-%d') as TRNINDT , CASE WHEN TP.TRNINTM IS NULL OR TRIM(TP.TRNINTM) = '' THEN '' ELSE STR_TO_DATE(TP.TRNINTM, '%H%i%s') END as TRNINTM , DATE_FORMAT(TP.TRCNLDT, '%Y-%m-%d') as TRCNLDT , CASE WHEN TP.TRCNLTM IS NULL OR TRIM(TP.TRCNLTM) = '' THEN '' ELSE STR_TO_DATE(TP.TRCNLTM, '%H%i%s') END as TRCNLTM , ${userInfo.schema}.FN_SY_USERNAM(TP.CREUSER) as CREUSER , DATE_FORMAT(TP.CREDATE, '%Y-%m-%d') as CREDATE , CASE WHEN TP.CRETIME IS NULL OR TRIM(TP.CRETIME) = '' THEN '' ELSE STR_TO_DATE(TP.CRETIME, '%H%i%s') END as CRETIME , ${userInfo.schema}.FN_SY_USERNAM(TP.LMOUSER) as LMOUSER , DATE_FORMAT(TP.LMODATE, '%Y-%m-%d') as LMODATE , CASE WHEN TP.LMOTIME IS NULL OR TRIM(TP.LMOTIME) = '' THEN '' ELSE STR_TO_DATE(TP.LMOTIME, '%H%i%s') END as LMOTIME , SUM(TI.SKUWEIG) AS TOTALWEIG , TW.ORDERWEIG , TP.UPDTCHK , TP.APROVYN , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'APROVYN' AND COMCDVL = TP.APROVYN AND COUSEYN = 'Y') AS APNAMLC , DATE_FORMAT(TP.APROVDT, '%Y-%m-%d') as APROVDT , CASE WHEN TP.APROVTM IS NULL OR TRIM(TP.APROVTM) = '' THEN '' ELSE STR_TO_DATE(TP.APROVTM, '%H%i%s') END as APROVTM FROM ${userInfo.schema}.TPLNHD TP INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = TP.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVOWMA MV ON MV.VOWNKEY = TP.VOWNKEY AND MV.VOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MH ON MH.VOWNKEY = TP.VOWNKEY AND MH.VEHICKY = TP.VEHICKY AND MH.VHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TP.WAREKEY AND MD.DOCCATE = TP.DOCCATE AND MD.DOCTYPE = TP.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCL ON MCL.COMCDKY = 'LOADKEY' AND MCL.COMCDVL = TP.LOADKEY AND MCL.COUSEYN = 'Y' LEFT JOIN ${userInfo.schema}.TPLNIT TI ON TI.WAREKEY = TP.WAREKEY AND TI.VHPLNKY = TP.VHPLNKY AND TI.TPISTAT != 'CANCEL' LEFT JOIN ( SELECT VHPLNKY, SUM(ALCWEIG) AS ORDERWEIG FROM ${userInfo.schema}.TPWPWG GROUP BY VHPLNKY ) TW ON TW.VHPLNKY = TP.VHPLNKY WHERE TP.WAREKEY = #{param.warekey}
AND TP.DOCTYPE = #{param.doctype}
AND REPLACE(MH.VHCFNAM, ' ', '') LIKE CONCAT('%', REPLACE(#{param.vhcfnam}, ' ', ''), '%')
AND TP.APROVYN = #{param.aprovyn}
AND TP.TPNSTAT IN
#{tpnstat}
AND TP.VHPDATE BETWEEN #{param.vhpdateFrom} AND #{param.vhpdateTo}
GROUP BY TP.WAREKEY, MW.WHNAMLC, TP.VHPLNKY, TP.VOWNKEY, MV.VONAMLC , TP.VEHICKY, MH.VHCFNAM, MH.VHCSNAM, MH.VHCVRYN, TP.VHCMAXW , MH.VHCTYPE, TP.DRVERNM, TP.DRVERPH, TP.DOCCATE, TP.DOCTYPE , MD.DOCCTNM, MD.DOCTYNM, TP.LOADKEY, MCL.COMCDTX, TP.TPNSTAT , TP.TPRILOC, TP.SPRILOC, TP.TRNMEMO, TP.MIXCUYN, TP.VHPDATE , TP.VHPTIME, TP.STPITDT, TP.STPITTM, TP.TRNINDT, TP.TRNINTM , TP.CREUSER, TP.CREDATE, TP.CRETIME, TP.LMOUSER, TP.LMODATE , TP.LMOTIME, TW.ORDERWEIG, TP.UPDTCHK, TP.APROVYN, TP.APROVDT , TP.APROVTM ORDER BY TP.VHPLNKY DESC

/* selectDispatchCurrentHeadOrder */ SELECT CONCAT(TP.WAREKEY, TP.VHPLNKY) AS ROWKEY , TP.WAREKEY , MW.WHNAMLC , TP.VHPLNKY , TP.VOWNKEY , MV.VONAMLC , TP.VEHICKY , MH.VHCFNAM , MH.VHCSNAM , MH.VHCVRYN , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'VHCTNCD' AND COMCDVL = MH.VHCTNCD AND COUSEYN = 'Y') AS VHNAMLC , TP.VHCMAXW , MH.VHCTYPE , TP.DRVERNM , TP.DRVERPH , TP.DOCCATE , TP.DOCTYPE , MD.DOCCTNM , MD.DOCTYNM , TP.LOADKEY , MCL.COMCDTX as LONAMLC , TP.TPNSTAT , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'TPNSTAT' AND COMCDVL = TP.TPNSTAT AND COUSEYN = 'Y') AS PLNAMLC , TP.TPRILOC , (SELECT LOCANAM FROM ${userInfo.schema}.MLOCMA WHERE WAREKEY = #{param.warekey} AND LOCTYPE = 'STP' AND LOUSEYN = 'Y' AND LOCAKEY = TP.TPRILOC) AS TRLOCML , TP.SPRILOC , (SELECT LOCANAM FROM ${userInfo.schema}.MLOCMA WHERE WAREKEY = #{param.warekey} AND LOCTYPE = 'STP' AND LOUSEYN = 'Y' AND LOCAKEY = TP.SPRILOC) AS SRLOCML , TP.TRNMEMO , TP.MIXCUYN , DATE_FORMAT(TP.VHPDATE, '%Y-%m-%d') as VHPDATE , CASE WHEN TP.VHPTIME IS NULL OR TRIM(TP.VHPTIME) = '' THEN '' ELSE STR_TO_DATE(TP.VHPTIME, '%H%i%s') END as VHPTIME , DATE_FORMAT(TP.STPITDT, '%Y-%m-%d') as STPITDT , CASE WHEN TP.STPITTM IS NULL OR TRIM(TP.STPITTM) = '' THEN '' ELSE STR_TO_DATE(TP.STPITTM, '%H%i%s') END AS STPITTM , DATE_FORMAT(TP.TRNINDT, '%Y-%m-%d') as TRNINDT , CASE WHEN TP.TRNINTM IS NULL OR TRIM(TP.TRNINTM) = '' THEN '' ELSE STR_TO_DATE(TP.TRNINTM, '%H%i%s') END as TRNINTM , DATE_FORMAT(TP.TRCNLDT, '%Y-%m-%d') as TRCNLDT , CASE WHEN TP.TRCNLTM IS NULL OR TRIM(TP.TRCNLTM) = '' THEN '' ELSE STR_TO_DATE(TP.TRCNLTM, '%H%i%s') END as TRCNLTM , ${userInfo.schema}.FN_SY_USERNAM(TP.CREUSER) as CREUSER , DATE_FORMAT(TP.CREDATE, '%Y-%m-%d') as CREDATE , CASE WHEN TP.CRETIME IS NULL OR TRIM(TP.CRETIME) = '' THEN '' ELSE STR_TO_DATE(TP.CRETIME, '%H%i%s') END as CRETIME , ${userInfo.schema}.FN_SY_USERNAM(TP.LMOUSER) as LMOUSER , DATE_FORMAT(TP.LMODATE, '%Y-%m-%d') as LMODATE , CASE WHEN TP.LMOTIME IS NULL OR TRIM(TP.LMOTIME) = '' THEN '' ELSE STR_TO_DATE(TP.LMOTIME, '%H%i%s') END as LMOTIME , SUM(TI.SKUWEIG) AS TOTALWEIG , TW.ORDERWEIG , TP.UPDTCHK , TP.APROVYN , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'APROVYN' AND COMCDVL = TP.APROVYN AND COUSEYN = 'Y') AS APNAMLC , DATE_FORMAT(TP.APROVDT, '%Y-%m-%d') as APROVDT , CASE WHEN TP.APROVTM IS NULL OR TRIM(TP.APROVTM) = '' THEN '' ELSE STR_TO_DATE(TP.APROVTM, '%H%i%s') END as APROVTM FROM ${userInfo.schema}.TPLNHD TP INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = TP.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVOWMA MV ON MV.VOWNKEY = TP.VOWNKEY AND MV.VOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MH ON MH.VOWNKEY = TP.VOWNKEY AND MH.VEHICKY = TP.VEHICKY AND MH.VHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TP.WAREKEY AND MD.DOCCATE = TP.DOCCATE AND MD.DOCTYPE = TP.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCL ON MCL.COMCDKY = 'LOADKEY' AND MCL.COMCDVL = TP.LOADKEY AND MCL.COUSEYN = 'Y' LEFT JOIN ${userInfo.schema}.TPLNIT TI ON TI.WAREKEY = TP.WAREKEY AND TI.VHPLNKY = TP.VHPLNKY INNER JOIN ( SELECT VHPLNKY, SUM(ALCWEIG) AS ORDERWEIG FROM ${userInfo.schema}.TPWPWG GROUP BY VHPLNKY
HAVING SUM(CASE WHEN WPLCFYN != 'Y' THEN 1 ELSE 0 END) = 0 AND SUM(CASE WHEN OOUCFYN != 'Y' THEN 1 ELSE 0 END) = 0 AND SUM(CASE WHEN SHPCFYN != 'Y' THEN 1 ELSE 0 END) = 0
HAVING SUM(CASE WHEN WPLCFYN = 'Y' THEN 1 ELSE 0 END) = 0 AND SUM(CASE WHEN OOUCFYN = 'Y' THEN 1 ELSE 0 END) = 0 AND SUM(CASE WHEN SHPCFYN = 'Y' THEN 1 ELSE 0 END) = 0
) TW ON TW.VHPLNKY = TP.VHPLNKY WHERE TP.WAREKEY = #{param.warekey}
AND TP.DOCTYPE = #{param.doctype}
AND TP.TPNSTAT != 'CANCEL'
AND TP.TPNSTAT NOT IN ('CANCEL', 'PLAN')
AND REPLACE(MH.VHCFNAM, ' ', '') LIKE CONCAT('%', REPLACE(#{param.vhcfnam}, ' ', ''), '%')
AND TP.APROVYN = #{param.aprovyn}
AND TP.TPNSTAT IN
#{tpnstat}
AND TP.VHPDATE BETWEEN #{param.vhpdateFrom} AND #{param.vhpdateTo}
GROUP BY TP.WAREKEY, MW.WHNAMLC, TP.VHPLNKY, TP.VOWNKEY, MV.VONAMLC , TP.VEHICKY, MH.VHCFNAM, MH.VHCSNAM, MH.VHCVRYN, TP.VHCMAXW , MH.VHCTYPE, TP.DRVERNM, TP.DRVERPH, TP.DOCCATE, TP.DOCTYPE , MD.DOCCTNM, MD.DOCTYNM, TP.LOADKEY, MCL.COMCDTX, TP.TPNSTAT , TP.TPRILOC, TP.SPRILOC, TP.TRNMEMO, TP.MIXCUYN, TP.VHPDATE , TP.VHPTIME, TP.STPITDT, TP.STPITTM, TP.TRNINDT, TP.TRNINTM , TP.CREUSER, TP.CREDATE, TP.CRETIME, TP.LMOUSER, TP.LMODATE , TP.LMOTIME, TW.ORDERWEIG, TP.UPDTCHK, TP.APROVYN, TP.APROVDT , TP.APROVTM ORDER BY TP.VHPLNKY DESC

mapper.update:
/* updateTplnhdAprovyn */
UPDATE ${userInfo.schema}.TPLNHD
   SET UPDTCHK = UPDTCHK + 1
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{userInfo.useract}
     , APROVYN = #{param.aprovyn}
     , APROVDT = DATE_FORMAT(NOW(), '%Y%m%d')
     , APROVTM = DATE_FORMAT(NOW(), '%H%i%s')

	 	, TPNSTAT = #{param.tpnstat}
		, TRCNLDT = DATE_FORMAT(NOW(), '%Y%m%d')
		, TRCNLTM = DATE_FORMAT(NOW(), '%H%i%s')

 WHERE VHPLNKY = #{param.vhplnky}
   AND WAREKEY = #{param.warekey}
   AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.TPLNHD WHERE VHPLNKY = #{param.vhplnky} AND WAREKEY = #{param.warekey})

/* updateTplnhd */
UPDATE ${userInfo.schema}.TPLNHD
   SET UPDTCHK = UPDTCHK + 1
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{userInfo.useract}

    	, VHCMAXW = #{param.vhcmaxw}
    	, MIXCUYN = #{param.mixcuyn}
    	, TPRILOC = #{param.tpriloc}
    	, SPRILOC = #{param.spriloc}
    	, TRNMEMO = #{param.trnmemo}
    	, DRVERNM = #{param.drvernm}
    	, DRVERPH = #{param.drverph}
    	, CORWEIG = #{param.corweig}

 WHERE VHPLNKY = #{param.vhplnky}
   AND WAREKEY = #{param.warekey}
   AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.TPLNHD WHERE VHPLNKY = #{param.vhplnky} AND WAREKEY = #{param.warekey})

/* updateTmTpwpwg */
UPDATE ${userInfo.schema}.TPWPWG
   SET UPDTCHK = UPDTCHK + 1
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{userInfo.useract}

     	, ARRIVYN = #{param.arrivyn}


     	, ALCWEIG = #{param.alcweig}

WHERE VHPLNKY = #{param.vhplnky}
  AND SHPPLKY = #{param.shpplky}
  AND PLNSIZE = #{param.plnsize}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.TPWPWG WHERE VHPLNKY = #{param.vhplnky} AND SHPPLKY = #{param.shpplky} AND PLNSIZE = #{param.plnsize})

		/* updateTpistat */
		UPDATE ${userInfo.schema}.TPLNIT
           SET TPISTAT = #{param.tpistat}
             , UPDTCHK = UPDTCHK + 1
             , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
 		     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
  		     , LMOUSER = #{userInfo.useract}

  		     , TRNCPDT = ''
  		     , TRNCPTM = ''


             , TRNCPDT = CASE WHEN TRNCPDT IS NULL OR TRIM(TRNCPDT) = '' THEN DATE_FORMAT(NOW(), '%Y%m%d') ELSE TRNCPDT END
    		 , TRNCPTM = CASE WHEN TRNCPTM IS NULL OR TRIM(TRNCPTM) = '' THEN DATE_FORMAT(NOW(), '%H%i%s') ELSE TRNCPTM END
    		 , BILDATE = CASE WHEN BILDATE IS NULL OR TRIM(BILDATE) = '' THEN DATE_FORMAT(NOW(), '%Y%m%d') ELSE BILDATE END

         WHERE VHPLNKY = #{param.vhplnky}
           AND VHPLNIT = #{param.vhplnit}
           AND WAREKEY = #{param.warekey}
           AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.TPLNIT WHERE VHPLNKY = #{param.vhplnky} AND VHPLNIT = #{param.vhplnit} AND WAREKEY = #{param.warekey})

mapper.select:
/* selectVehicleOrderList */ SELECT CONCAT(WH.WAREKEY, WH.SHPPLKY) as ROWKEY , WH.SHPPLKY , WH.WAREKEY , MW.WHNAMLC , WH.REGIKEY , MR.RENAMLC , CASE WHEN WH.SHPWEIG < 1000 THEN ROUND(WH.SHPWEIG / 1000) ELSE WH.SHPWEIG / 1000 END AS SHPWEIG , WH.SKUGRKY , MG.GRPKYNM , MG.SZGUBUN , WH.DESTKEY , CASE WHEN WH.DESTKEY IS NULL OR TRIM(WH.DESTKEY) = '' THEN WH.DENAMLC WHEN MDE.DENAMLC IS NULL OR TRIM(MDE.DENAMLC) = '' THEN WH.DENAMLC ELSE MDE.DENAMLC END AS DENAMLC , WH.DESADDR , DATE_FORMAT(WH.WPLDATE, '%Y-%m-%d') as WPLDATE , CASE WHEN WH.WPLTIME IS NULL OR TRIM(WH.WPLTIME) = '' THEN '' ELSE STR_TO_DATE(WH.WPLTIME, '%H%i%s') END as WPLTIME , WH.DOCCATE , WH.DOCTYPE , MD.DOCCTNM , MD.DOCTYNM , WH.WPLSTAT , MC.COMCDTX as WPLAMLC , CASE WHEN WH.REMWEIG < 1000 THEN ROUND(WH.REMWEIG / 1000) ELSE WH.REMWEIG / 1000 END AS REMWEIG , ROUND(WH.REMWEIG / 1000) as GDRMWEG , DATE_FORMAT(WH.CREDATE, '%Y-%m-%d') as CREDATE , CASE WHEN WH.CRETIME IS NULL OR TRIM(WH.CRETIME) = '' THEN '' ELSE STR_TO_DATE(WH.CRETIME, '%H%i%s') END as CRETIME , ${userInfo.schema}.FN_SY_USERNAM(WH.CREUSER) as CREUSER , DATE_FORMAT(WH.LMODATE, '%Y-%m-%d') as LMODATE , CASE WHEN WH.LMOTIME IS NULL OR TRIM(WH.LMOTIME) = '' THEN '' ELSE STR_TO_DATE(WH.LMOTIME, '%H%i%s') END as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(WH.LMOUSER) as LMOUSER , WH.UPDTCHK , SUM(WI.SKUWEIG) as TOTALWEIG , ( SELECT CASE WHEN SUM(WI2.SKUWEIG) = 0 THEN 0 WHEN SUM(WI2.SKUWEIG) < 1000 THEN ROUND(SUM(WI2.SKUWEIG) / 1000) ELSE SUM(WI2.SKUWEIG) / 1000 END FROM ${userInfo.schema}.WPLNIT WI2 WHERE WI2.SHPPLKY = WH.SHPPLKY AND WI2.CHKDISP = 'N' AND WI2.WPLITST != 'CANCEL') as EMERWEIG FROM ${userInfo.schema}.WPLNHD WH INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = WH.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MREGMA MR ON MR.REGIKEY = WH.REGIKEY AND MR.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MGRPMA MG ON MG.SKUGRKY = WH.SKUGRKY AND MG.GRUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = WH.WAREKEY AND MD.DOCCATE = WH.DOCCATE AND MD.DOCTYPE = WH.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MC ON MC.COMCDKY = 'WPLSTAT' AND MC.COMCDVL = WH.WPLSTAT AND MC.COUSEYN = 'Y' LEFT JOIN ${userInfo.schema}.WPLNIT WI ON WI.SHPPLKY = WH.SHPPLKY LEFT JOIN ${userInfo.schema}.MDESMA MDE ON MDE.CUSTKEY = WH.OWNERKY AND MDE.REGIKEY = WH.REGIKEY AND MDE.DESTKEY = WH.DESTKEY WHERE WH.WAREKEY = #{param.warekey} AND (WH.WPLSTAT = 'NEW' OR WH.WPLSTAT = 'ING') AND WH.REMWEIG > 0
AND WH.REGIKEY IN
#{regikey}
AND WH.WPLDATE BETWEEN #{param.wpldateFrom} AND #{param.wpldateTo}
AND WH.DOCTYPE = #{param.doctype}
AND WH.SHPPLKY IN
#{shpplky}
GROUP BY WH.SHPPLKY, WH.WAREKEY, MW.WHNAMLC, WH.REGIKEY, MR.RENAMLC, WH.SHPWEIG, WH.SKUGRKY, MG.GRPKYNM, MG.SZGUBUN, WH.WPLDATE, WH.WPLTIME, WH.DOCCATE, WH.DOCTYPE, MD.DOCCTNM, MD.DOCTYNM, WH.WPLSTAT, MC.COMCDTX, WH.REMWEIG, WH.CREDATE, WH.CRETIME, WH.CREUSER, WH.LMODATE, WH.LMOTIME, WH.LMOUSER, WH.UPDTCHK ORDER BY WH.SHPPLKY DESC

/* selectVehicleOrderItemList */ SELECT CONCAT(WI.WAREKEY, WI.SHPPLKY, WI.SHPPLIT) as ROWKEY , WI.SHPPLKY , WI.SHPPLIT , WI.WPLITST , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'WPLITST' AND COMCDVL = WI.WPLITST AND COUSEYN = 'Y') AS WPLNAMC , WI.WAREKEY , WI.CUSTCOD , CASE WHEN WI.CUSTCOD IS NULL OR TRIM(WI.CUSTCOD) != '' THEN WI.CUSTNAM WHEN MCU.CUNAMLC IS NULL OR TRIM(MCU.CUNAMLC) != '' THEN WI.CUSTNAM ELSE MCU.CUNAMLC END AS CUSTNAM , WI.OWNRNAM , WI.OWNERKY , CASE WHEN WI.OWNERKY IS NULL OR TRIM(WI.OWNERKY) != '' THEN WI.OWNRNAM WHEN MCO.CUNAMLC IS NULL OR TRIM(MCO.CUNAMLC) != '' THEN WI.OWNRNAM ELSE MCO.CUNAMLC END AS OWNRNAM , WI.REGIORG , RO.RENAMLC AS RONAMLC , WI.DESTORG , CASE WHEN WI.DESTORG IS NULL OR TRIM(WI.DESTORG) = '' THEN WI.DEORGNM WHEN MDO.DENAMLC IS NULL OR TRIM(MDO.DENAMLC) = '' THEN WI.DEORGNM ELSE MDO.DENAMLC END AS DEORGNM , WI.REGIMOD , RM.RENAMLC AS RMNAMLC , WI.DESTMOD , CASE WHEN WI.DESTMOD IS NULL OR TRIM(WI.DESTMOD) = '' THEN WI.DEMODNM WHEN MDM.DENAMLC IS NULL OR TRIM(MDM.DENAMLC) = '' THEN WI.DEMODNM ELSE MDM.DENAMLC END AS DEMODNM , WI.DEMDMAN , WI.DEMPOCD , WI.DEMDADR , CASE WHEN (WI.DEMDADR IS NULL OR TRIM(WI.DEMDADR) = '') AND (WI.DEMPOCD IS NULL OR TRIM(WI.DEMPOCD) = '') THEN '' WHEN (WI.DEMPOCD IS NULL OR TRIM(WI.DEMPOCD) = '') AND (WI.DEMDADR IS NOT NULL OR TRIM(WI.DEMDADR) != '') THEN WI.DEMDADR ELSE CONCAT('(', WI.DEMPOCD, ') ', WI.DEMDADR) END AS STOCKADDR , WI.DEMDTLN , DATE_FORMAT(WI.POSHPDT, '%Y-%m-%d') as POSHPDT , CASE WHEN WI.POSHPTM IS NULL OR TRIM(WI.POSHPTM) = '' THEN '' ELSE STR_TO_DATE(WI.POSHPTM, '%H%i%s') END as POSHPTM , WS.POSHPDY , WI.SKUGRKY , MG.GRPKYNM , WI.SKUMKEY , WI.SKUDESC , WI.SKULENG , WI.SKUWIDT , WI.SKUTHIC , WI.SKUWEIG , WI.PLANQTY , WI.STKMEMO , WI.ITEMCOD , MCI.COMCDVL AS ITEMMLC , WI.PURCNUM , WI.ORDERLN , WI.CHKDISP , WI.GROSSWD , WI.GROSSLN , WI.GROSSTH , WI.GROSSWG , WI.SUOMKEY , WI.EMSKUYN , WI.STOCKKY , WS.BTRCATE , WS.ADDCOKY , WS.STOCKKY , DATE_FORMAT(WI.SHPLIMT, '%Y-%m-%d') as SHPLIMT , DATE_FORMAT(WI.DELVDSR, '%Y-%m-%d') as DELVDSR , WI.BTRFSTC , DATE_FORMAT(WI.CREDATE, '%Y-%m-%d') as CREDATE , CASE WHEN WI.CRETIME IS NULL OR TRIM(WI.CRETIME) = '' THEN '' ELSE STR_TO_DATE(WI.CRETIME, '%H%i%s') END as CRETIME , ${userInfo.schema}.FN_SY_USERNAM(WI.CREUSER) as CREUSER , DATE_FORMAT(WI.LMODATE, '%Y-%m-%d') as LMODATE , CASE WHEN WI.LMOTIME IS NULL OR TRIM(WI.LMOTIME) = '' THEN '' ELSE STR_TO_DATE(WI.LMOTIME, '%H%i%s') END as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(WI.LMOUSER) as LMOUSER , WI.UPDTCHK , WS.BTRCATE , (SELECT BTRCNAM FROM ${userInfo.schema}.BTRCAT WHERE BTRCATE = WS.BTRCATE) AS BTRCNAM , WS.ADDCOKY , MCB.COMCDTX AS ADDNAML , WS.LOCAKEY , MLO.LOCANAM , WS.LOLAYER , WI.DEMODYN , WS.FNCUSKY , WS.FCNAMLC , WS.RCVDCKY , WS.RCVDCIT , WS.RCVDCDT , WS.RCVDCTM , WS.LOTAT01 , WS.LOTAT02 , WS.LOTAT03 , WS.STLOTNB FROM ${userInfo.schema}.WPLNIT WI INNER JOIN ${userInfo.schema}.MREGMA RO ON RO.REGIKEY = WI.REGIORG AND RO.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MGRPMA MG ON MG.SKUGRKY = WI.SKUGRKY AND MG.GRUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCI ON MCI.COMCDKY = 'ITEMCOD' AND MCI.COMCDVL = WI.ITEMCOD AND MCI.COUSEYN = 'Y'
LEFT JOIN ${userInfo.schema}.WSTKKY WS ON WS.STOCKKY = WI.STOCKKY INNER JOIN ${userInfo.schema}.MREGMA RM ON RM.REGIKEY = WI.REGIMOD AND RM.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.BADDCO BA ON WS.ADDCOKY = BA.ADDCOKY INNER JOIN ${userInfo.schema}.MCODEM MCB ON MCB.COMCDKY = 'ADDSIKY' AND MCB.COMCDVL = BA.ADDSIKY AND MCB.COUSEYN = 'Y' LEFT JOIN ${userInfo.schema}.MCUSMA MCU ON MCU.CUSTKEY = WI.CUSTCOD AND MCU.CUDELYN = 'Y' LEFT JOIN ${userInfo.schema}.MCUSMA MCO ON MCO.CUSTKEY = WI.OWNERKY AND MCO.CUDELYN = 'Y' LEFT JOIN ${userInfo.schema}.MDESMA MDO ON MDO.REGIKEY = WI.REGIORG AND MDO.CUSTKEY = WI.OWNERKY AND MDO.DESTKEY = WI.DESTORG AND MDO.DEUSEYN = 'Y' LEFT JOIN ${userInfo.schema}.MDESMA MDM ON MDM.REGIKEY = WI.REGIMOD AND MDM.CUSTKEY = WI.OWNERKY AND MDM.DESTKEY = WI.DESTMOD AND MDM.DEUSEYN = 'Y'
LEFT JOIN ${userInfo.schema}.MLOCMA MLO ON MLO.WAREKEY = WS.WAREKEY AND MLO.AREAKEY = WS.AREAKEY AND MLO.LOCAKEY = WS.LOCAKEY AND MLO.LOUSEYN = 'Y' WHERE WI.SHPPLKY = #{param.shpplky} AND WI.WAREKEY = #{param.warekey}
AND WI.CHKDISP = #{param.chkdisp}
AND WI.WPLITST != #{param.wplitst}
AND MG.SZGUBUN >= #{param.szgubun}
ORDER BY WI.WAREKEY ASC, WS.AREAKEY ASC, WS.LOCAKEY ASC, WS.LOLAYER DESC, WI.SHPPLKY ASC, WI.SHPPLIT ASC

/* selectVehicleList */ SELECT MV.VEHICKY , MCV.COMCDTX as CONAMLC , MCD.COMCDTX as DLNAMLC , MV.VHCSNAM , MV.VHCFNAM , MV.VHCTYPE , MCH.COMCDTX as VTNAMLC , MCT.COMCDTX as CDNAMLC , MV.VHCMAXW , MV.VHCVRYN , MV.VHCMEMO , MCS.COMCDTX as STNAMLC , MV.VOWNKEY , MO.VONAMLC , MV.DRVERNM , MV.DRVERPH , DATE_FORMAT(MV.CREDATE, '%Y-%m-%d') as CREDATE , CASE WHEN MV.CRETIME IS NULL OR TRIM(MV.CRETIME) = '' THEN '' ELSE STR_TO_DATE(MV.CRETIME, '%H%i%s') END as CRETIME , ${userInfo.schema}.FN_SY_USERNAM(MV.CREUSER) as CREUSER , DATE_FORMAT(MV.LMODATE, '%Y-%m-%d') as LMODATE , CASE WHEN MV.LMOTIME IS NULL OR TRIM(MV.LMOTIME) = '' THEN '' ELSE STR_TO_DATE(MV.LMOTIME, '%H%i%s') END as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(MV.LMOUSER) as LMOUSER FROM ${userInfo.commonSchema}.MVHCMA MV INNER JOIN ${userInfo.commonSchema}.MVOWMA MO ON MO.VOWNKEY = MV.VOWNKEY AND MO.VOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCV ON MCV.COMCDKY = 'VHCOPTY' AND MCV.COMCDVL = MV.VHCOPTY AND MCV.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCD ON MCD.COMCDKY = 'DLVTYPE' AND MCD.COMCDVL = MV.DLVTYPE AND MCD.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCH ON MCH.COMCDKY = 'VHCTYPE' AND MCH.COMCDVL = MV.VHCTYPE AND MCH.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCT ON MCT.COMCDKY = 'VHCTNCD' AND MCT.COMCDVL = MV.VHCTNCD AND MCT.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MCODEM MCS ON MCS.COMCDKY = 'VHCSTAT' AND MCS.COMCDVL = MV.VHCSTAT AND MCS.COUSEYN = 'Y' WHERE MV.VHUSEYN = 'Y' AND ((MV.VHCTYPE = (SELECT VHCTYPE FROM ${userInfo.schema}.MGRPMA WHERE GRUSEYN = 'Y' AND SKUGRKY = #{param.skugrky})) OR MV.VHCVRYN = 'Y')
AND (MV.PUBLCYN = 'Y' OR (MV.PUBLCYN = 'N' AND MV.DMWPLNM = #{param.dmwplnm}))
AND (MV.PUBLCYN = 'Y' OR (MV.PUBLCYN = 'N' AND MV.DMWPLNM = REPLACE(LOWER(#{userInfo.schema}), '_', '-')))

/* selectOperationDayLog */ SELECT TP.WAREKEY , MW.WHNAMLC , TP.DOCCATE , TP.DOCTYPE , MD.DOCCTNM , MD.DOCTYNM , MV.VHCSNAM , MV.VHCFNAM , MV.DRVERNM , MO.VONAMLC
, SUM(CASE WHEN DATE_FORMAT(TP.TRNINDT, '%d') = #{day} THEN 1 ELSE 0 END) AS TRNINDT${day}
, SUM( CASE WHEN DATE_FORMAT(TP.TRNINDT, '%d') IN
#{day}
THEN 1 ELSE 0 END ) AS totalTrnindtCnt FROM ${userInfo.schema}.TPLNHD TP INNER JOIN ${userInfo.commonSchema}.MVHCMA MV ON MV.VOWNKEY = TP.VOWNKEY AND MV.VEHICKY = TP.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVOWMA MO ON MO.VOWNKEY = TP.VOWNKEY AND MO.VOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TP.WAREKEY AND MD.DOCCATE = TP.DOCCATE AND MD.DOCTYPE = TP.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = TP.WAREKEY AND MW.WHUSEYN = 'Y' WHERE TP.TPNSTAT = 'FINISH' AND DATE_FORMAT(TP.TRNINDT, '%Y%m') = #{param.targetMonth} AND TP.WAREKEY = #{param.warekey}
AND REPLACE(MV.VHCFNAM, ' ', '') LIKE CONCAT('%', REPLACE(#{param.vhcfnam}, ' ', ''), '%')
AND REPLACE(MO.VONAMLC, ' ', '') LIKE CONCAT('%', REPLACE(#{param.vonamlc}, ' ', ''), '%')
AND REPLACE(MV.DRVERNM, ' ', '') LIKE CONCAT('%', REPLACE(#{param.drvernm}, ' ', ''), '%')
GROUP BY TP.DOCCATE, TP.DOCTYPE, MD.DOCCTNM, MD.DOCTYNM , MV.VHCSNAM, MV.VHCFNAM, MV.DRVERNM, MO.VONAMLC , TP.WAREKEY, MW.WHNAMLC

/* selectOperationMonthLog */ SELECT TP.DOCCATE , TP.DOCTYPE , MD.DOCCTNM , MD.DOCTYNM , TP.VEHICKY , MV.VHCSNAM , MV.VHCFNAM , MV.DRVERNM , TP.VOWNKEY , MO.VONAMLC , COUNT(DISTINCT DATE_FORMAT(TP.TRNINDT, '%Y-%m-%d')) as TRNMONT FROM ${userInfo.schema}.TPLNHD TP INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TP.WAREKEY AND MD.DOCCATE = TP.DOCCATE AND MD.DOCTYPE = TP.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MV ON MV.VOWNKEY = TP.VOWNKEY AND MV.VEHICKY = TP.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVOWMA MO ON MO.VOWNKEY = TP.VOWNKEY AND MO.VOUSEYN = 'Y' WHERE TP.TPNSTAT = 'FINISH' AND DATE_FORMAT(TP.TRNINDT, '%Y%m') = #{param.targetMonth} AND TP.WAREKEY = #{param.warekey}
AND REPLACE(MV.VHCFNAM, ' ', '') LIKE CONCAT('%', REPLACE(#{param.vhcfnam}, ' ', ''), '%')
AND REPLACE(MO.VONAMLC, ' ', '') LIKE CONCAT('%', REPLACE(#{param.vonamlc}, ' ', ''), '%')
AND REPLACE(MV.DRVERNM, ' ', '') LIKE CONCAT('%', REPLACE(#{param.drvernm}, ' ', ''), '%')
GROUP BY TP.DOCCATE, TP.DOCTYPE, MD.DOCCTNM, MD.DOCTYNM , TP.VEHICKY, MV.VHCSNAM, MV.VHCFNAM, TP.VOWNKEY , MO.VONAMLC, MV.DRVERNM

mapper.insert:
/* insertTplnhd */ INSERT INTO ${userInfo.schema}.TPLNHD ( WAREKEY, VHPLNKY, VOWNKEY, VEHICKY, DOCCATE, DOCTYPE, LOADKEY, VHPDATE, VHPTIME, TRNMEMO, TPRILOC, SPRILOC, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, VHCMAXW, DRVERNM, DRVERPH, MIXCUYN, CORWEIG
, APROVYN, APROVDT, APROVTM
) VALUES ( #{param.warekey}, #{param.vhplnky}, #{param.vownkey}, #{param.vehicky}, #{param.doccate}, #{param.doctype}, #{param.loadkey}, DATE_FORMAT(NOW(), '%Y%m%d'), DATE_FORMAT(NOW(), '%H%i%s'), #{param.trnmemo}, #{param.tpriloc}, #{param.spriloc}, DATE_FORMAT(NOW(), '%Y%m%d'), DATE_FORMAT(NOW(), '%H%i%s'), #{userInfo.useract}, DATE_FORMAT(NOW(), '%Y%m%d'), DATE_FORMAT(NOW(), '%H%i%s'), #{userInfo.useract}, #{param.vhcmaxw}, #{param.drvernm}, #{param.drverph}, #{param.mixcuyn}, #{param.corweig}
, #{param.aprovyn}, DATE_FORMAT(NOW(), '%Y%m%d'), DATE_FORMAT(NOW(), '%H%i%s')
)

mapper.update:
/* tmUpdateWplnit */
UPDATE ${userInfo.schema}.WPLNIT
   SET CHKDISP = #{param.chkdisp}
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{userInfo.useract}
     , UPDTCHK = UPDTCHK + 1
WHERE SHPPLKY = #{param.shpplky}
  AND SHPPLIT = #{param.shpplit}
  AND WAREKEY = #{param.warekey}
  AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.WPLNIT WHERE SHPPLKY = #{param.shpplky} AND SHPPLIT = #{param.shpplit} AND WAREKEY = #{param.warekey})

/* tmUpdateWplnhd */
UPDATE ${userInfo.schema}.WPLNHD
   SET REMWEIG = #{param.remweig}
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{userInfo.useract}
     , UPDTCHK = #{param.updtchk} + 1
WHERE SHPPLKY = #{param.shpplky}
  AND UPDTCHK = #{param.updtchk}

	AND WAREKEY = #{param.warekey}

mapper.delete:
/* deleteTmTpwpwg */
DELETE FROM ${userInfo.schema}.TPWPWG
 WHERE VHPLNKY = #{param.vhplnky}
   AND SHPPLKY = #{param.shpplky}
   AND PLNSIZE = #{param.plnsize}

mapper.select:
/* selectTpwpwgList */ SELECT TW.VHPLNKY , TW.SHPPLKY , TW.ALCWEIG , TW.PLNSIZE , MG.GRPKYNM , TW.REGIKEY , MR.RENAMLC , TW.WPLCFYN , TW.OOUCFYN , TW.SHPCFYN , TW.ARRIVYN , TW.UPDTCHK , DATE_FORMAT(TW.CREDATE, '%Y-%m-%d') as CREDATE , CASE WHEN TW.CRETIME IS NULL OR TRIM(TW.CRETIME) = '' THEN '' ELSE STR_TO_DATE(TW.CRETIME, '%H%i%s') END as CRETIME , ${userInfo.schema}.FN_SY_USERNAM(TW.CREUSER) as CREUSER , DATE_FORMAT(TW.LMODATE, '%Y-%m-%d') as LMODATE , CASE WHEN TW.LMOTIME IS NULL OR TRIM(TW.LMOTIME) = '' THEN '' ELSE STR_TO_DATE(TW.LMOTIME, '%H%i%s') END as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(TW.LMOUSER) as LMOUSER FROM ${userInfo.schema}.TPWPWG TW INNER JOIN ${userInfo.schema}.MREGMA MR ON MR.REGIKEY = TW.REGIKEY AND MR.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MGRPMA MG ON MG.SKUGRKY = TW.PLNSIZE AND MG.GRUSEYN = 'Y' WHERE TW.VHPLNKY = #{param.vhplnky}
AND TW.SHPPLKY = #{param.shpplky}
AND TW.WPLCFYN = 'N' AND TW.OOUCFYN = 'N' AND TW.SHPCFYN = 'N' AND TW.ARRIVYN = 'N'

/* selectLocationFilterList */ SELECT ML.WAREKEY , ML.AREAKEY , ML.LOCAKEY , ML.LOCANAM FROM ${userInfo.schema}.MLOCMA ML INNER JOIN ( SELECT DISTINCT LOCAKEY FROM ${userInfo.schema}.MEQLOC WHERE EQUIPKY IN ( SELECT DISTINCT ME.EQUIPKY FROM ${userInfo.schema}.MEQLOC ME INNER JOIN ${userInfo.schema}.WSTKKY WS ON WS.STOCKKY IN
#{item.stockky}
AND WS.LOCAKEY = ME.LOCAKEY WHERE ME.ELUSEYN = 'Y' ) )AS A ON A.LOCAKEY = ML.LOCAKEY WHERE ML.LOCTYPE = 'STP' AND ML.WAREKEY = #{param.warekey} AND ML.LOUSEYN = 'Y'

/* selectMaxLayerByLocation */
SELECT MAX(WS.LOLAYER) as MAXLAYER
FROM ${userInfo.schema}.WSTKKY WS
WHERE WS.WAREKEY = #{param.warekey}
  AND WS.AREAKEY = #{param.areakey}
  AND WS.LOCAKEY = #{param.locakey}
